#include <bits/stdc++.h>
using namespace std;
const int N=100005;
int n,m,tr[2][N];
void add(int now,int t)
{
	while(now<=n)
    {
		tr[t][now]++;
		now+=(now&(-now));
	}
}
int sum(int now,int t)
{
	int ans=0;
	while(now)
    {
		ans+=tr[t][now];
		now-=now&(-now);
	}
	return ans;
}
int main()
{
    cin>>n>>m;
    for(int i=1;i<=m;i++)
    {
        int op,l,r;
        cin>>op>>l>>r;
        if(op==1)
        {
            add(l,0);
            add(r,1);
        }
        else
        {
            cout<<(sum(r,0)-sum(l-1,1))<<'\n';
        }
    }
    return 0;
}
